using System.Numerics;

namespace InFalsus.Crypto;

/// <summary>
/// Calculate Secret Unsigned Numbers.
/// </summary>
public static class SecretNumbers
{
    private static readonly BigInteger Int4096Mask =
        (BigInteger.One << 4096) - 1;

    private static readonly BigInteger ULongMask = (BigInteger.One << 64) - 1;

    private static readonly BigInteger Divider = BigInteger.Parse(
        "");

    private static readonly BigInteger[] Adders =
    [
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-")
    ];

    public static ulong GetSecretUlong(int seed)
    {
        BigInteger curr = 0;
        BigInteger multiplier = seed;
        for (int i = Adders.Length - 1; i >= 0; i--)
        {
            curr = (curr * multiplier) & Int4096Mask;
            curr = (curr + Adders[i]) & Int4096Mask;
        }

        BigInteger value = curr / Divider;
        if (value.GetBitLength() > 64)
        {
            throw new ArgumentException(
                "invalid secret number, check your seed");
        }

        return (ulong)((curr / Divider) & ULongMask);
    }
}